UPDATE t_p28211681_photo_secure_web.legal_documents
SET content = REPLACE(
  content,
  '<p>4.2. Я уведомлён(а), что вправе отозвать настоящее согласие, направив Оператору письменное уведомление на адрес электронной почты support@foto-mix.ru с пометкой «Отзыв согласия на обработку персональных данных».</p>
<p>4.3. В случае отзыва согласия Оператор вправе продолжить обработку персональных данных без согласия при наличии оснований, предусмотренных Федеральным законом от 27.07.2006 № 152-ФЗ «О персональных данных».</p>',
  '<p>4.2. Я уведомлён(а), что вправе отозвать настоящее согласие, направив Оператору письменное уведомление на адрес электронной почты support@foto-mix.ru с пометкой «Отзыв согласия на обработку персональных данных».</p>
<p>4.3. При этом отзыв согласия может означать прекращение предоставления Оператором услуг Пользователю, так как отказ от предоставления согласия на обработку персональных данных может повлечь невозможность оказания сервисов Оператора, пользования Личным кабинетом и исполнения Договора с Пользователем.</p>
<p>4.4. В случае отзыва Пользователем согласия на обработку персональных данных Оператор вправе продолжить обработку персональных данных без согласия Пользователя при наличии оснований, установленных Федеральным законом от 27.07.2006 г. №152-ФЗ «О персональных данных» и Федеральным законом от 07.08.2001 г. №115-ФЗ «О противодействии легализации (отмыванию) доходов, полученных преступным путем, и финансированию терроризма».</p>'
)
WHERE slug = 'personal-data';
